// Snowfall Point Lookup — single-file Cloudflare Worker application
// Consistent Rolling Cycles 1.3: sums NOAA 6-hour grids for every 24/48/72-hour ending cycle.

const APP_HTML_BASE64 = "";
const NOAA_BASE = "https://www.nohrsc.noaa.gov/snowfall_v2/data/";

function decodeAppHtml() {
  const binary = atob(APP_HTML_BASE64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return new TextDecoder().decode(bytes);
}

function jsonResponse(payload, status = 200) {
  return new Response(JSON.stringify(payload), {
    status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Cache-Control": "no-store",
      "Access-Control-Allow-Origin": "*"
    }
  });
}

function validNoaaPath(path) {
  if (!path || path.includes("..") || path.includes("\\")) return false;

  const fixedPeriod = /^\d{6}\/sfav2_CONUS_(6h|24h|48h|72h)_\d{10}\.tif$/;
  const seasonal = /^\d{6}\/sfav2_CONUS_\d{10}_to_\d{10}\.tif$/;
  return fixedPeriod.test(path) || seasonal.test(path);
}


function analysisEndFromPath(path) {
  const matches = [...path.matchAll(/(\d{10})(?=\.tif|_to_)/g)];
  if (!matches.length) return null;
  const stamp = matches.at(-1)[1];
  const year = Number(stamp.slice(0, 4));
  const month = Number(stamp.slice(4, 6)) - 1;
  const day = Number(stamp.slice(6, 8));
  const hour = Number(stamp.slice(8, 10));
  const date = new Date(Date.UTC(year, month, day, hour));
  return Number.isNaN(date.getTime()) ? null : date;
}

function cacheSecondsForPath(path) {
  const analysisEnd = analysisEndFromPath(path);
  if (!analysisEnd) return 900;
  const ageMs = Date.now() - analysisEnd.getTime();
  // NOHRSC regenerates analyses for five days as late reports arrive.
  // Keep those files fresh; older archived grids can be cached longer.
  return ageMs <= 6 * 24 * 60 * 60 * 1000 ? 300 : 30 * 24 * 60 * 60;
}

async function relayNoaaFile(request, url, ctx) {
  if (request.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, OPTIONS",
        "Access-Control-Allow-Headers": "Accept, Content-Type",
        "Access-Control-Max-Age": "86400"
      }
    });
  }

  if (request.method !== "GET") return jsonResponse({ error: "Method not allowed." }, 405);

  const path = url.searchParams.get("path") || "";
  if (!validNoaaPath(path)) {
    return jsonResponse({
      error: "Invalid NOAA snowfall-file path.",
      received_path: path
    }, 400);
  }

  const targetUrl = NOAA_BASE + path;
  const cacheSeconds = cacheSecondsForPath(path);
  const cache = caches.default;
  const cacheKey = new Request(new URL(`/__noaa_cache_v13/${path}`, url.origin).toString(), { method: "GET" });
  const cached = await cache.match(cacheKey);
  if (cached) return cached;

  let upstream;
  try {
    upstream = await fetch(targetUrl, {
      headers: {
        "Accept": "image/tiff,application/octet-stream;q=0.9,*/*;q=0.8",
        "User-Agent": "SnowfallPointLookup/1.3"
      },
      cf: { cacheEverything: true, cacheTtl: cacheSeconds }
    });
  } catch (error) {
    return jsonResponse({
      error: "The NOAA server could not be reached.",
      target_url: targetUrl
    }, 502);
  }

  if (!upstream.ok) {
    const status = upstream.status === 404 ? 404 : 502;
    return jsonResponse({
      error: upstream.status === 404
        ? "NOAA does not have that snowfall grid."
        : `NOAA returned HTTP ${upstream.status}.`,
      target_url: targetUrl
    }, status);
  }

  const headers = new Headers(upstream.headers);
  headers.set("Content-Type", "image/tiff");
  headers.set("Content-Disposition", `inline; filename="${path.split("/").pop()}"`);
  headers.set("Cache-Control", `public, max-age=${cacheSeconds}`);
  headers.set("Access-Control-Allow-Origin", "*");
  headers.delete("Set-Cookie");

  const response = new Response(upstream.body, { status: 200, headers });
  ctx.waitUntil(cache.put(cacheKey, response.clone()));
  return response;
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/api/noaa") {
      return relayNoaaFile(request, url, ctx);
    }

    if (url.pathname === "/api/health") {
      return jsonResponse({
        status: "ok",
        service: "Snowfall Point Lookup",
        version: "1.3-consistent-rolling-cycles",
        noaa_base: NOAA_BASE
      });
    }

    if (request.method !== "GET" && request.method !== "HEAD") {
      return new Response("Method not allowed", { status: 405 });
    }

    if (url.pathname !== "/" && url.pathname !== "/index.html") {
      return new Response("Not found", { status: 404 });
    }

    return new Response(request.method === "HEAD" ? null : decodeAppHtml(), {
      status: 200,
      headers: {
        "Content-Type": "text/html; charset=utf-8",
        "Cache-Control": "public, max-age=300",
        "X-Content-Type-Options": "nosniff",
        "Referrer-Policy": "strict-origin-when-cross-origin",
        "Permissions-Policy": "geolocation=(), camera=(), microphone=()"
      }
    });
  }
};
